import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 政策與封地管理：王國不是打完就沒事","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/policies-fiefs.md","filePath":"bannerlord/policies-fiefs.md"}'),l={name:"bannerlord/policies-fiefs.md"};function i(h,t,o,n,s,b){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="騎砍2-政策與封地管理-王國不是打完就沒事" tabindex="-1">騎砍2 | 政策與封地管理：王國不是打完就沒事 <a class="header-anchor" href="#騎砍2-政策與封地管理-王國不是打完就沒事" aria-label="Permalink to &quot;騎砍2 | 政策與封地管理：王國不是打完就沒事&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>打下城很爽，但管城很煩。每個城要總督、要駐軍、要蓋建築、要顧繁榮度。這篇把城鎮管理的眉角講清楚。</p><hr><h2 id="一、城鎮管理面板" tabindex="-1">一、城鎮管理面板 <a class="header-anchor" href="#一、城鎮管理面板" aria-label="Permalink to &quot;一、城鎮管理面板&quot;">​</a></h2><p>點你的城鎮 → 管理城鎮：</p><table tabindex="0"><thead><tr><th>指標</th><th>影響</th></tr></thead><tbody><tr><td>繁榮度</td><td>稅收基礎，越高錢越多</td></tr><tr><td>忠誠度</td><td>低於 25 會叛變</td></tr><tr><td>糧食</td><td>不夠會飢餓，繁榮度下降</td></tr><tr><td>安全感</td><td>低會出盜賊</td></tr><tr><td>駐軍</td><td>防守力量，但要花錢養</td></tr></tbody></table><hr><h2 id="二、建築優先級" tabindex="-1">二、建築優先級 <a class="header-anchor" href="#二、建築優先級" aria-label="Permalink to &quot;二、建築優先級&quot;">​</a></h2><p>每個城可以蓋建築，但欄位有限：</p><table tabindex="0"><thead><tr><th style="text-align:center;">優先級</th><th>建築</th><th>效果</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td>穀倉</td><td>糧食儲備上限↑，圍城撐更久</td></tr><tr><td style="text-align:center;">2</td><td>果園</td><td>糧食產量↑，支撐更高繁榮度</td></tr><tr><td style="text-align:center;">3</td><td>市場</td><td>稅收↑</td></tr><tr><td style="text-align:center;">4</td><td>城牆</td><td>防禦力↑</td></tr><tr><td style="text-align:center;">5</td><td>軍營</td><td>駐軍上限↑</td></tr></tbody></table><blockquote><p>永遠先蓋穀倉和果園。糧食是一切繁榮的基礎。</p></blockquote><hr><h2 id="三、總督指派" tabindex="-1">三、總督指派 <a class="header-anchor" href="#三、總督指派" aria-label="Permalink to &quot;三、總督指派&quot;">​</a></h2><h3 id="_3-1-為什麼要總督" tabindex="-1">3.1 為什麼要總督 <a class="header-anchor" href="#_3-1-為什麼要總督" aria-label="Permalink to &quot;3.1 為什麼要總督&quot;">​</a></h3><p>把一個夥伴/家族成員設為城鎮總督：</p><ul><li>總督的文化跟城鎮相同 → 忠誠度 +1</li><li>總督的技能加成（管理、工程等）會套用在城鎮</li><li>裝 Governor Handle Issues MOD → 總督自動處理城鎮隨機事件</li></ul><h3 id="_3-2-選誰當總督" tabindex="-1">3.2 選誰當總督 <a class="header-anchor" href="#_3-2-選誰當總督" aria-label="Permalink to &quot;3.2 選誰當總督&quot;">​</a></h3><table tabindex="0"><thead><tr><th>優先看</th><th>原因</th></tr></thead><tbody><tr><td>文化</td><td>跟城鎮文化相同最重要</td></tr><tr><td>管理學</td><td>影響稅收和建設速度</td></tr><tr><td>工程學</td><td>影響建築速度</td></tr></tbody></table><hr><h2 id="四、村莊管理" tabindex="-1">四、村莊管理 <a class="header-anchor" href="#四、村莊管理" aria-label="Permalink to &quot;四、村莊管理&quot;">​</a></h2><p>每個城鎮有 2-4 個附屬村莊：</p><ul><li>村莊的產出決定城鎮的原料供應</li><li>村莊被掠奪 → 原料停產 → 城鎮經濟崩</li><li>裝 Improved Garrisons MOD → 可以派巡邏隊保護村莊</li></ul><hr><h2 id="五、政策推薦" tabindex="-1">五、政策推薦 <a class="header-anchor" href="#五、政策推薦" aria-label="Permalink to &quot;五、政策推薦&quot;">​</a></h2><p>當你有 5+ 個城鎮時，這些政策特別有價值：</p><table tabindex="0"><thead><tr><th>政策</th><th>效果</th><th>適合情境</th></tr></thead><tbody><tr><td>土地稅</td><td>城鎮稅收 +5%</td><td>城多時收入可觀</td></tr><tr><td>公民權</td><td>城鎮忠誠度 +1</td><td>征服不同文化城鎮時</td></tr><tr><td>道路收費</td><td>村莊收入 +3%</td><td>村莊多的王國</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./kingdom-management.html">騎砍2 | 王國管理深度指南</a></li><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',36)])])}const p=a(l,[["render",i]]);export{u as __pageData,p as default};
